update group_buy_order
set lock_count = lock_count + 1, update_time= now()
where id = (
    select latest_id
    from (
        select max(id) as latest_id
        from group_buy_order
        where team_id = #{teamId}
          and status = 0
          and valid_end_time > now()
          and lock_count < target_count
    ) t
)


update group_buy_order
set complete_count = complete_count + 1, update_time= now()
where id = (
    select latest_id
    from (
        select max(id) as latest_id
        from group_buy_order
        where team_id = #{teamId}
          and status = 0
          and complete_count < target_count
    ) t
)

update group_buy_order
set lock_count = lock_count - 1, update_time= now()
where id = (
    select latest_id
    from (
        select max(id) as latest_id
        from group_buy_order
        where team_id = #{teamId}
          and lock_count > 0
    ) t
)

update group_buy_order
set status = 1, update_time= now()
where id = (
    select latest_id
    from (
        select max(id) as latest_id
        from group_buy_order
        where team_id = #{teamId}
          and status = 0
    ) t
)

update group_buy_order
set status = 2,
    update_time = now()
where activity_id = #{activityId}
  and status = 0
  and team_id in (
    select distinct team_id
    from group_buy_order_list
    where activity_id = #{activityId}
      and goods_id = #{goodsId}
)

